class TransactionProcessor {
    static let shared = TransactionProcessor()
    
    private var accounts: [String: Account] = [:]
    private var transactions: [Transaction] = []
    
    private init() {
        loadData()
    }
    
    private func loadData() {
        let loadedAccounts = DataStore.shared.loadAccounts()
        for account in loadedAccounts {
            accounts[account.accountNumber] = account
        }
        transactions = DataStore.shared.loadTransactions()
    }
    
    func createAccount(accountNumber: String, initialBalance: Decimal, accountType: String, currency: String) -> Account {
        let account = Account(accountNumber: accountNumber, balance: initialBalance, accountType: accountType, currency: currency)
        accounts[accountNumber] = account
        saveAccounts()
        return account
    }
    
    func getAccount(accountNumber: String) -> Account? {
        return accounts[accountNumber]
    }
    
    func processTransaction(from fromAccount: String, to toAccount: String, amount: Decimal, type: Transaction.TransactionType) -> Result<Transaction, TransactionError> {
        
        guard var sourceAccount = accounts[fromAccount] else {
            return .failure(.accountNotFound)
        }
        
        guard var destinationAccount = accounts[toAccount] else {
            return .failure(.accountNotFound)
        }
        
        guard amount > 0 else {
            return .failure(.invalidAmount)
        }
        
        guard sourceAccount.balance >= amount else {
            return .failure(.insufficientFunds)
        }
        
        sourceAccount.balance -= amount
        destinationAccount.balance += amount
        
        accounts[fromAccount] = sourceAccount
        accounts[toAccount] = destinationAccount
        
        let transaction = Transaction(
            id: UUID().uuidString,
            fromAccount: fromAccount,
            toAccount: toAccount,
            amount: amount,
            timestamp: Date(),
            type: type,
            status: .completed
        )
        
        if SecurityManager.shared.validateTransaction(transaction) {
            transactions.append(transaction)
            saveAccounts()
            saveTransactions()
            return .success(transaction)
        } else {
            return .failure(.validationFailed)
        }
    }
    
    func getAccountBalance(accountNumber: String) -> Decimal? {
        return accounts[accountNumber]?.balance
    }
    
    func getTransactionHistory(for accountNumber: String) -> [Transaction] {
        return transactions.filter { $0.fromAccount == accountNumber || $0.toAccount == accountNumber }
    }
    
    func getAllTransactions() -> [Transaction] {
        return transactions
    }
    
    private func saveAccounts() {
        let accountArray = Array(accounts.values)
        DataStore.shared.saveAccounts(accountArray)
    }
    
    private func saveTransactions() {
        DataStore.shared.saveTransactions(transactions)
    }
    
    enum TransactionError: Error {
        case accountNotFound
        case insufficientFunds
        case invalidAmount
        case validationFailed
    }
